import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Contracten","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/contracts.md","filePath":"nl/features/contracts.md"}'),i={name:"nl/features/contracts.md"};function o(l,e,c,s,u,d){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="contracten" tabindex="-1">Contracten <a class="header-anchor" href="#contracten" aria-label="Permalink to &quot;Contracten&quot;">​</a></h1><p>Beheer terugkerende serviceovereenkomsten en huurcontracten met automatische facturatieschema&#39;s.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>Contracten vertegenwoordigen lopende overeenkomsten met klanten — zoals maandelijkse servicecontracten, huurovereenkomsten of onderhoudsplannen. Ze kunnen automatisch facturen genereren volgens een vast schema.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>De contractenmodule is optioneel. Schakel deze in via <strong>Bedrijf &gt; Functies</strong> als je hem niet in de navigatie ziet.</p></div><h2 id="een-contract-aanmaken" tabindex="-1">Een contract aanmaken <a class="header-anchor" href="#een-contract-aanmaken" aria-label="Permalink to &quot;Een contract aanmaken&quot;">​</a></h2><ol><li>Ga naar <strong>Contracten &gt; Nieuw contract</strong></li><li>Vul in: <ul><li><strong>Naam</strong> — Een beschrijvende titel (bijv. &quot;Maandelijkse schoonmaakdienst&quot;)</li><li><strong>Klant</strong> — De contractpartij</li><li><strong>Bedrag</strong> — Het terugkerende facturatiebedrag</li><li><strong>Herhaling</strong> — Hoe vaak factureren (wekelijks, maandelijks, per kwartaal, jaarlijks)</li><li><strong>Startdatum</strong> — Wanneer het contract begint</li><li><strong>Einddatum</strong> — Optionele einddatum</li><li><strong>Omschrijving</strong> — Voorwaarden en details</li></ul></li><li>Klik op <strong>Opslaan</strong></li></ol><h2 id="contractstatussen" tabindex="-1">Contractstatussen <a class="header-anchor" href="#contractstatussen" aria-label="Permalink to &quot;Contractstatussen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Actief</strong></td><td>Momenteel van kracht, genereert facturen</td></tr><tr><td><strong>Inactief</strong></td><td>Gepauzeerd — er worden geen facturen gegenereerd</td></tr></tbody></table><h2 id="automatische-facturatie" tabindex="-1">Automatische facturatie <a class="header-anchor" href="#automatische-facturatie" aria-label="Permalink to &quot;Automatische facturatie&quot;">​</a></h2><p>Actieve contracten met een herhalingsschema genereren automatisch facturen bij elke facturatieperiode. Het systeem:</p><ol><li>Maakt een conceptfactuur aan op basis van de contractvoorwaarden</li><li>Past de juiste klant, bedrag en omschrijving toe</li><li>Volgt je factuurnummeringsinstellingen</li></ol><p>Je kunt gegenereerde facturen handmatig bekijken en versturen, of automatische verzending instellen.</p><h2 id="koppelen-aan-objecten" tabindex="-1">Koppelen aan objecten <a class="header-anchor" href="#koppelen-aan-objecten" aria-label="Permalink to &quot;Koppelen aan objecten&quot;">​</a></h2><p>Contracten kunnen worden gekoppeld aan <a href="/nl/features/objects">objecten/activa</a> voor verhuurbeheer:</p><ul><li>Koppel een contract aan een pand, voertuig of apparaat</li><li>Houd bij welke objecten momenteel verhuurd zijn en aan wie</li><li>Bekijk de contractgeschiedenis per object</li></ul><h2 id="statistieken" tabindex="-1">Statistieken <a class="header-anchor" href="#statistieken" aria-label="Permalink to &quot;Statistieken&quot;">​</a></h2><p>De contractenlijstpagina toont samenvattende statistieken:</p><ul><li>Totaal aantal actieve contracten</li><li>Totale contractwaarde</li><li>Contracten per herhalingstype</li></ul><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">​</a></h2><ul><li><strong>Status wijzigen</strong> — Activeer of deactiveer meerdere contracten</li><li><strong>Archiveren</strong> — Verplaats naar archief</li><li><strong>Herstellen</strong> — Haal gearchiveerde contracten terug</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Gebruik contracten samen met <a href="/nl/features/recurring-invoices">terugkerende facturen</a> voor verschillende facturatiescenario&#39;s</li><li>Koppel contracten aan objecten voor volledig verhuurbeheer</li><li>Stel einddatums in om een melding te ontvangen voordat contracten aflopen</li><li>Gebruik het contractenfilter om actief vs. inactief in een oogopslag te zien</li></ul>',23)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
